class MemoryRecord:
    id: "str"
    entity: "str"
    attribute: "str"
    value: "str"
    source: "typing.Optional[str]"
    created_at: "int"
    updated_at: "int"
    def __init__(self, *, id: "str", entity: "str", attribute: "str", value: "str", source: "typing.Optional[str]", created_at: "int", updated_at: "int"):
        self.id = id
        self.entity = entity
        self.attribute = attribute
        self.value = value
        self.source = source
        self.created_at = created_at
        self.updated_at = updated_at

    def __str__(self):
        return "MemoryRecord(id={}, entity={}, attribute={}, value={}, source={}, created_at={}, updated_at={})".format(self.id, self.entity, self.attribute, self.value, self.source, self.created_at, self.updated_at)

    def __eq__(self, other):
        if self.id != other.id:
            return False
        if self.entity != other.entity:
            return False
        if self.attribute != other.attribute:
            return False
        if self.value != other.value:
            return False
        if self.source != other.source:
            return False
        if self.created_at != other.created_at:
            return False
        if self.updated_at != other.updated_at:
            return False
        return True

