# EngramError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class EngramError(Exception):
    pass

_UniffiTempEngramError = EngramError

class EngramError:  # type: ignore
    class Crypto(_UniffiTempEngramError):

        def __repr__(self):
            return "EngramError.Crypto({})".format(repr(str(self)))
    _UniffiTempEngramError.Crypto = Crypto # type: ignore
    class Vault(_UniffiTempEngramError):

        def __repr__(self):
            return "EngramError.Vault({})".format(repr(str(self)))
    _UniffiTempEngramError.Vault = Vault # type: ignore
    class Store(_UniffiTempEngramError):

        def __repr__(self):
            return "EngramError.Store({})".format(repr(str(self)))
    _UniffiTempEngramError.Store = Store # type: ignore
    class InvalidInput(_UniffiTempEngramError):

        def __repr__(self):
            return "EngramError.InvalidInput({})".format(repr(str(self)))
    _UniffiTempEngramError.InvalidInput = InvalidInput # type: ignore

EngramError = _UniffiTempEngramError # type: ignore
del _UniffiTempEngramError


class _UniffiConverterTypeEngramError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return EngramError.Crypto(
                _UniffiConverterString.read(buf),
            )
        if variant == 2:
            return EngramError.Vault(
                _UniffiConverterString.read(buf),
            )
        if variant == 3:
            return EngramError.Store(
                _UniffiConverterString.read(buf),
            )
        if variant == 4:
            return EngramError.InvalidInput(
                _UniffiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, EngramError.Crypto):
            return
        if isinstance(value, EngramError.Vault):
            return
        if isinstance(value, EngramError.Store):
            return
        if isinstance(value, EngramError.InvalidInput):
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, EngramError.Crypto):
            buf.write_i32(1)
        if isinstance(value, EngramError.Vault):
            buf.write_i32(2)
        if isinstance(value, EngramError.Store):
            buf.write_i32(3)
        if isinstance(value, EngramError.InvalidInput):
            buf.write_i32(4)



class _UniffiConverterOptionalString(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiConverterString.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiConverterString.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiConverterString.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")



